functions.example_code:
-- 统计总行数
SELECT COUNT(*) AS total FROM users;

-- 统计非空城市数
SELECT COUNT(city) AS has_city FROM users;

-- 统计去重城市数
SELECT COUNT(DISTINCT city) AS unique_cities FROM users;

-- 计算所有订单的总金额
SELECT SUM(amount) AS total_amount FROM orders;

-- 计算每个用户的总消费金额
SELECT user_id, SUM(amount) AS total_spent
FROM orders GROUP BY user_id;

-- 计算所有订单的平均金额
SELECT AVG(amount) AS avg_amount FROM orders;

-- 保留两位小数
SELECT ROUND(AVG(amount), 2) AS avg_amount FROM orders;

-- 将每个城市的用户名列在一起
SELECT city, GROUP_CONCAT(name) AS users
FROM users GROUP BY city;

-- 指定分隔符和排序
SELECT city, GROUP_CONCAT(name ORDER BY name SEPARATOR ' | ') AS users
FROM users GROUP BY city;

-- 将姓和名拼接为完整姓名
SELECT CONCAT(first_name, ' ', last_name) AS full_name FROM employees;

-- 带分隔符拼接地址
SELECT CONCAT(city, '·', district) AS address FROM users;

-- 从第 3 位开始截取 2 个字符
SELECT SUBSTRING('abcdef', 3, 2) AS result;
-- 结果: cd

-- 从倒数第 2 位截取到末尾
SELECT SUBSTRING('abcdef', -2) AS result;
-- 结果: ef

-- 格式化为 '年-月-日' 格式
SELECT DATE_FORMAT(order_date, '%Y-%m-%d') AS formatted_date FROM orders;

-- 格式化为中文日期
SELECT DATE_FORMAT(order_date, '%Y年%m月%d日') AS chinese_date FROM orders;

-- 只提取月份
SELECT DATE_FORMAT(order_date, '%Y年%m月') AS month FROM orders;

-- 增加7天
SELECT DATE_ADD('2024-01-01', INTERVAL 7 DAY) AS result;
-- 结果: 2024-01-08

-- 增加1个月
SELECT DATE_ADD('2024-01-01', INTERVAL 1 MONTH) AS result;
-- 结果: 2024-02-01

-- 增加1年
SELECT order_date, DATE_ADD(order_date, INTERVAL 1 YEAR) AS warranty_end
FROM orders;

-- 取整
SELECT ROUND(12.7) AS result;
-- 结果: 13

-- 保留两位小数
SELECT ROUND(3.14159, 2) AS result;
-- 结果: 3.14

-- 计算平均分并保留1位小数
SELECT ROUND(AVG(score), 1) AS avg_score FROM students;

-- 为没有电话号码的用户显示'暂无'
SELECT name, COALESCE(phone, '暂无') AS contact FROM users;

-- 多级回退
SELECT COALESCE(phone, email, '无联系方式') AS contact FROM users;

-- 将备注为空的值显示为'无备注'
SELECT name, IFNULL(remark, '无备注') AS remark FROM users;

-- 计算时处理 NULL
SELECT name, salary + IFNULL(bonus, 0) AS total_income FROM employees;

-- 字符串转整数
SELECT CAST('123' AS SIGNED) AS num;
-- 结果: 123

-- 字符串转日期
SELECT CAST('2024-01-15' AS DATE) AS dt;

-- 整数带小数位
SELECT CAST(42 AS DECIMAL(10,2)) AS num;
-- 结果: 42.00

-- 提取 JSON 字段中的某个属性
SELECT name, JSON_EXTRACT(profile, '$.age') AS age
FROM users;

-- 提取嵌套属性
SELECT JSON_EXTRACT(profile, '$.address.city') AS city FROM users;

-- 使用 -> 简写
SELECT profile->'$.age' AS age FROM users;

-- 查询最高分
SELECT MAX(score) AS top_score FROM students;

-- 按班级分组取最高分
SELECT class, MAX(score) AS top FROM students GROUP BY class;

-- 查询最低分
SELECT MIN(score) AS low_score FROM students;

-- 找最早订单日期
SELECT MIN(order_date) AS first_order FROM orders;

-- 去除首尾空格
SELECT TRIM('  hello  ') AS r;
-- 结果: 'hello'

-- 去除指定字符
SELECT TRIM(LEADING 'x' FROM 'xxhello') AS r;

-- 获取今天
SELECT CURRENT_DATE AS today;

-- 给每行加上今日日期
SELECT order_id, CURRENT_DATE AS today FROM orders;

-- 获取当前时间戳
SELECT NOW() AS ts;

-- 记录创建时间
INSERT INTO logs(message, created_at) VALUES('hello', NOW());

-- 按年统计订单数
SELECT YEAR(order_date) AS y, COUNT(*) AS cnt
FROM orders GROUP BY YEAR(order_date);

-- 按月统计
SELECT MONTH(order_date) AS m, COUNT(*) AS cnt
FROM orders GROUP BY MONTH(order_date);

-- 使用 - 拼接
SELECT CONCAT_WS('-', '2024', '01', '15') AS d;
-- 结果: 2024-01-15

-- 拼接地址（NULL 自动跳过）
SELECT CONCAT_WS(', ', province, city, district) AS addr FROM users;

-- 比较中英文长度
SELECT name, CHAR_LENGTH(name) AS chars, LENGTH(name) AS bytes
FROM users;

-- 解析中文日期
SELECT STR_TO_DATE('2024年01月15日', '%Y年%m月%d日') AS dt;
-- 结果: 2024-01-15

-- 减 7 天
SELECT DATE_SUB('2024-01-08', INTERVAL 7 DAY) AS r;
-- 结果: 2024-01-01

-- 当前时间戳
SELECT UNIX_TIMESTAMP() AS ts;

-- 转换
SELECT UNIX_TIMESTAMP('2024-01-01 00:00:00') AS ts;

-- 是否及格
SELECT name, score, IF(score >= 60, '及格', '不及格') AS pass
FROM students;

-- 把空串转为 NULL
SELECT name, NULLIF(remark, '') AS remark_clean FROM users;

-- 防除零
SELECT a / NULLIF(b, 0) FROM t;

-- 类型转换
SELECT CONVERT('123', SIGNED) AS num;

-- 字符集转换
SELECT CONVERT(name USING utf8mb4) FROM users;

-- 计算 2 的 10 次方
SELECT POWER(2, 10) AS r;
-- 结果: 1024

-- 平方
SELECT POWER(side, 2) AS area FROM squares;

-- 构造 JSON 对象
SELECT JSON_OBJECT('name', name, 'age', age) AS profile
FROM users;
